  ownerApproverId: string;
  secondConfirmation: boolean;
  secondConfirmerId: string;
  hasFunds: boolean;
  financialHistoryCount: number;
  finalState: 'requested' | 'owner_approved' | 'second_confirmed' | 'archived' | 'rejected' | 'blocked_has_funds';
  auditNote: string;
