  userId: string;
  withdrawalId: string | null;
  bankName: string;        // decrypted only in memory; never returned in full
  accountHolder: string;
  routing: string;
  accountNumber: string;
  swift: string;
  iban: string;
  accountNumberLast4: string;
  isInternational: boolean;
